const SofatelcomApp={config:{refreshInterval:30000,notificationDuration:5000,autoSaveInterval:120000,apiBaseUrl:window.location.origin},state:{currentUser:null,notifications:[],intervalHandlers:[]}};document.addEventListener('DOMContentLoaded',function(){initializeApp();setupGlobalEventListeners();initializeFeatherIcons();setupNotifications();setupAutoSave();});function initializeApp(){console.log('Initialisation de Sofatelcom PUR...');checkConnectivity();initializeTooltips();setupFormValidation();setupTables();startRefreshIntervals();console.log('Sofatelcom PUR initialisé avec succès');}function setupGlobalEventListeners(){window.addEventListener('offline',handleOffline);window.addEventListener('online',handleOnline);window.addEventListener('error',handleGlobalError);window.addEventListener('resize',debounce(handleWindowResize,250));window.addEventListener('beforeunload',handleBeforeUnload);document.addEventListener('click',handleDataActionClicks);}function initializeFeatherIcons(){if(typeof feather!=='undefined'){feather.replace({'stroke-width':2,width:20,height:20});}}function initializeTooltips(){const tooltipTriggerList=[].slice.call(document.querySelectorAll('[data-bs-toggle="tooltip"]'));tooltipTriggerList.map(function(tooltipTriggerEl){return new bootstrap.Tooltip(tooltipTriggerEl);});}function setupFormValidation(){const forms=document.querySelectorAll('.needs-validation');Array.from(forms).forEach(form=>{form.addEventListener('submit',function(event){if(!form.checkValidity()){event.preventDefault();event.stopPropagation();showNotification('Veuillez corriger les erreurs dans le formulaire','warning');}form.classList.add('was-validated');});});}function setupTables(){const tables=document.querySelectorAll('table:not(.no-hover)');tables.forEach(table=>{table.classList.add('table-hover');});setupTableSorting();}function setupTableSorting(){const sortableHeaders=document.querySelectorAll('th[data-sortable]');sortableHeaders.forEach(header=>{header.style.cursor='pointer';header.classList.add('user-select-none');header.addEventListener('click',function(){const table=this.closest('table');const column=Array.from(this.parentNode.children).indexOf(this);const isAscending=this.classList.contains('sort-asc');sortableHeaders.forEach(h=>{h.classList.remove('sort-asc','sort-desc');});this.classList.add(isAscending ? 'sort-desc':'sort-asc');sortTable(table,column,!isAscending);});});}function sortTable(table,column,ascending=true){const tbody=table.querySelector('tbody');const rows=Array.from(tbody.querySelectorAll('tr'));rows.sort((a,b)=>{const aValue=a.cells[column].textContent.trim();const bValue=b.cells[column].textContent.trim();const aNum=parseFloat(aValue);const bNum=parseFloat(bValue);if(!isNaN(aNum)&&!isNaN(bNum)){return ascending ? aNum-bNum:bNum-aNum;}const aDate=Date.parse(aValue);const bDate=Date.parse(bValue);if(!isNaN(aDate)&&!isNaN(bDate)){return ascending ? aDate-bDate:bDate-aDate;}return ascending ? aValue.localeCompare(bValue,'fr',{numeric:true,sensitivity:'base'}):bValue.localeCompare(aValue,'fr',{numeric:true,sensitivity:'base'});});rows.forEach(row=>tbody.appendChild(row));}function startRefreshIntervals(){if(document.querySelector('.dashboard-stats')){const statsInterval=setInterval(refreshDashboardStats,SofatelcomApp.config.refreshInterval);SofatelcomApp.state.intervalHandlers.push(statsInterval);}const notificationInterval=setInterval(checkNewNotifications,SofatelcomApp.config.refreshInterval);SofatelcomApp.state.intervalHandlers.push(notificationInterval);}function refreshDashboardStats(){fetch('/api/stats').then(response=>response.json()).then(data=>updateDashboardStats(data)).catch(error=>console.error('Erreur refresh stats:',error));}function updateDashboardStats(stats){Object.keys(stats).forEach(key=>{const element=document.querySelector(`[data-stat="${key}"]`);if(element){const newValue=stats[key];const currentValue=parseInt(element.textContent);if(newValue!==currentValue){animateCounterUpdate(element,currentValue,newValue);}}});}function animateCounterUpdate(element,from,to){const duration=1000;const steps=30;const stepValue=(to-from)/steps;let current=from;let step=0;const interval=setInterval(()=>{step++;current+=stepValue;if(step>=steps){element.textContent=to;clearInterval(interval);}else{element.textContent=Math.round(current);}},duration/steps);element.classList.add('pulse');setTimeout(()=>element.classList.remove('pulse'),duration);}function checkNewNotifications(){if(getCurrentUserRole()==='technicien'){fetch('/interventions/api/check-new-interventions').then(response=>response.json()).then(data=>{if(data.new_interventions>0){showNotification(`${data.new_interventions}nouvelle(s)intervention(s)assignée(s)`,'info',true);if(Notification.permission==='granted'){new Notification('Sofatelcom PUR',{body:`${data.new_interventions}nouvelle(s)intervention(s)assignée(s)`,icon:'/static/icon.png',tag:'new-interventions'});}}}).catch(error=>console.error('Erreur check notifications:',error));}}function setupNotifications(){if('Notification' in window&&Notification.permission==='default'){Notification.requestPermission();}if(!document.getElementById('notification-container')){const container=document.createElement('div');container.id='notification-container';container.className='position-fixed top-0 end-0 p-3';container.style.zIndex='9999';document.body.appendChild(container);}}function showNotification(message,type='info',persistent=false){const container=document.getElementById('notification-container');if(!container)return;const notification=document.createElement('div');notification.className=`alert alert-${type==='error' ? 'danger':type}alert-dismissible fade show`;notification.setAttribute('role','alert');notification.innerHTML=`<div class="d-flex align-items-center"><i data-feather="${getNotificationIcon(type)}" class="me-2"></i><div class="flex-grow-1">${message}</div><button type="button" class="btn-close" data-bs-dismiss="alert"></button></div>`;container.appendChild(notification);if(typeof feather!=='undefined'&&typeof feather.replace==='function'){try{feather.replace();}catch(e){console.warn('Feather.replace()error:',e);}}if(!persistent){setTimeout(()=>{if(notification.parentNode){notification.classList.remove('show');setTimeout(()=>notification.remove(),150);}},SofatelcomApp.config.notificationDuration);}SofatelcomApp.state.notifications.push({message,type,timestamp:new Date(),element:notification});}function getNotificationIcon(type){const icons={success:'check-circle',info:'info',warning:'alert-triangle',error:'alert-circle',danger:'alert-circle'};return icons[type]||'info';}function setupAutoSave(){const forms=document.querySelectorAll('[data-auto-save]');forms.forEach(form=>{const interval=setInterval(()=>{autoSaveForm(form);},SofatelcomApp.config.autoSaveInterval);SofatelcomApp.state.intervalHandlers.push(interval);});}function autoSaveForm(form){const formData=new FormData(form);const autoSaveUrl=form.dataset.autoSave;if(!autoSaveUrl)return;fetch(autoSaveUrl,{method:'POST',body:formData}).then(response=>response.json()).then(data=>{if(data.success){showAutoSaveIndicator();}}).catch(error=>console.error('Erreur sauvegarde auto:',error));}function showAutoSaveIndicator(){let indicator=document.getElementById('auto-save-indicator');if(!indicator){indicator=document.createElement('div');indicator.id='auto-save-indicator';indicator.className='position-fixed bottom-0 end-0 m-3 alert alert-success alert-dismissible fade';indicator.innerHTML=`<small><i data-feather="save" class="me-1"></i>Sauvegarde automatique</small>`;document.body.appendChild(indicator);}indicator.classList.add('show');if(typeof feather!=='undefined'&&typeof feather.replace==='function'){try{feather.replace();}catch(e){console.warn('Feather.replace()error:',e);}}setTimeout(()=>{indicator.classList.remove('show');},2000);}function handleDataActionClicks(event){const element=event.target.closest('[data-action]');if(!element)return;const action=element.dataset.action;const params=element.dataset.params ? JSON.parse(element.dataset.params):{};switch(action){case 'refresh':location.reload();break;case 'print':window.print();break;case 'export':exportData(params);break;case 'copy':copyToClipboard(params.text||element.textContent);break;default:console.warn('Action non reconnue:',action);}}function exportData(params){const{type='csv',selector,filename}=params;if(type==='csv'&&selector){const table=document.querySelector(selector);if(table){exportTableToCSV(table,filename);}}}function exportTableToCSV(table,filename='export.csv'){const rows=table.querySelectorAll('tr:not(.no-export)');const csvContent=Array.from(rows).map(row=>{const cells=row.querySelectorAll('th,td');return Array.from(cells).map(cell=>{return `"${cell.textContent.trim().replace(/"/g,'""')}"`;}).join(',');}).join('\n');downloadCSV(csvContent,filename);}function downloadCSV(content,filename){const blob=new Blob([content],{type:'text/csv;charset=utf-8;'});const link=document.createElement('a');if(link.download!==undefined){const url=URL.createObjectURL(blob);link.setAttribute('href',url);link.setAttribute('download',filename);link.style.visibility='hidden';document.body.appendChild(link);link.click();document.body.removeChild(link);URL.revokeObjectURL(url);}}function copyToClipboard(text){if(navigator.clipboard){navigator.clipboard.writeText(text).then(()=>{showNotification('Copié dans le presse-papiers','success');});}else{const textArea=document.createElement('textarea');textArea.value=text;document.body.appendChild(textArea);textArea.focus();textArea.select();try{document.execCommand('copy');showNotification('Copié dans le presse-papiers','success');}catch(err){showNotification('Erreur lors de la copie','error');}document.body.removeChild(textArea);}}function checkConnectivity(){if(!navigator.onLine){showNotification('Vous êtes hors ligne','warning',true);}}function handleOffline(){showNotification('Connexion perdue. Certaines fonctionnalités peuvent être limitées.','warning',true);document.body.classList.add('offline');}function handleOnline(){showNotification('Connexion rétablie','success');document.body.classList.remove('offline');}function handleGlobalError(event){if(event&&typeof event.error!=='undefined'){console.error('Erreur JavaScript:',event.error);}else{console.error('Erreur JavaScript(event):',event);}if(window.location.hostname==='localhost'||window.location.hostname==='127.0.0.1'){let message='Erreur JavaScript inconnue';if(event&&event.error){if(typeof event.error==='object'&&event.error!==null){message=event.error.message||event.error.toString();}else{message=event.error;}}else if(event&&event.message){message=event.message;}else{message=JSON.stringify(event);}showNotification(`Erreur:${message}`,'error');}}function handleWindowResize(){const signaturePads=document.querySelectorAll('.signature-pad');signaturePads.forEach(canvas=>{if(canvas.signaturePad){canvas.signaturePad.resizeCanvas();}});const tooltips=document.querySelectorAll('[data-bs-toggle="tooltip"]');tooltips.forEach(el=>{const tooltip=bootstrap.Tooltip.getInstance(el);if(tooltip)tooltip.dispose();});initializeTooltips();}function handleBeforeUnload(event){const forms=document.querySelectorAll('form[data-warn-unsaved]');const hasUnsavedChanges=Array.from(forms).some(form=>formHasUnsavedChanges(form));if(hasUnsavedChanges){event.preventDefault();event.returnValue='';}}function formHasUnsavedChanges(form){const formData=new FormData(form);const originalData=form.dataset.originalData;if(!originalData)return false;const currentData=JSON.stringify(Array.from(formData.entries()));return currentData!==originalData;}function getCurrentUserRole(){const userElement=document.querySelector('[data-user-role]');return userElement ? userElement.dataset.userRole:null;}function debounce(func,wait,immediate){let timeout;return function executedFunction(){const context=this;const args=arguments;const later=function(){timeout=null;if(!immediate)func.apply(context,args);};const callNow=immediate&&!timeout;clearTimeout(timeout);timeout=setTimeout(later,wait);if(callNow)func.apply(context,args);};}function throttle(func,limit){let inThrottle;return function(){const args=arguments;const context=this;if(!inThrottle){func.apply(context,args);inThrottle=true;setTimeout(()=>inThrottle=false,limit);}};}window.addEventListener('beforeunload',function(){SofatelcomApp.state.intervalHandlers.forEach(handler=>{clearInterval(handler);});const tooltips=document.querySelectorAll('[data-bs-toggle="tooltip"]');tooltips.forEach(el=>{const tooltip=bootstrap.Tooltip.getInstance(el);if(tooltip)tooltip.dispose();});});window.SofatelcomApp=SofatelcomApp;window.showNotification=showNotification;window.copyToClipboard=copyToClipboard;window.exportTableToCSV=exportTableToCSV;